import json
import pickle
import base64
from kafka import KafkaConsumer
from kafka.errors import KafkaError
import logging
from typing import Dict, Callable, Any
import threading
from datetime import datetime

logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)


class TransactionProcessor:
    def __init__(self, bootstrap_servers='localhost:9092', group_id='transaction-processor-group'):
        self.bootstrap_servers = bootstrap_servers
        self.group_id = group_id
        self.consumer = None
        self.message_handlers: Dict[str, Callable] = {}
        self.running = False
        
    def register_handler(self, message_type: str, handler: Callable):
        self.message_handlers[message_type] = handler
        logger.info(f"Registered handler for message type: {message_type}")
    
    def deserialize_message(self, message_value: bytes) -> Any:
        try:
            decoded = json.loads(message_value.decode('utf-8'))
            return decoded
        except (json.JSONDecodeError, UnicodeDecodeError):
            try:
                return pickle.loads(message_value)
            except Exception:
                try:
                    decoded_b64 = base64.b64decode(message_value)
                    return pickle.loads(decoded_b64)
                except Exception as e:
                    logger.error(f"Failed to deserialize message: {e}")
                    return None
    
    def process_message(self, message):
        try:
            deserialized_data = self.deserialize_message(message.value)
            
            if deserialized_data is None:
                logger.error("Failed to deserialize message")
                return
            
            if isinstance(deserialized_data, dict):
                message_type = deserialized_data.get('type', 'unknown')
                
                if message_type in self.message_handlers:
                    handler = self.message_handlers[message_type]
                    handler(deserialized_data)
                else:
                    logger.warning(f"No handler registered for message type: {message_type}")
            else:
                if hasattr(deserialized_data, '__class__'):
                    class_name = deserialized_data.__class__.__name__
                    if class_name in self.message_handlers:
                        handler = self.message_handlers[class_name]
                        handler(deserialized_data)
                    else:
                        logger.warning(f"No handler registered for class: {class_name}")
                
        except Exception as e:
            logger.error(f"Error processing message: {e}")
    
    def start_consuming(self, topics):
        try:
            self.consumer = KafkaConsumer(
                *topics,
                bootstrap_servers=self.bootstrap_servers,
                group_id=self.group_id,
                auto_offset_reset='earliest',
                enable_auto_commit=True,
                value_deserializer=None
            )
            
            self.running = True
            logger.info(f"Started consuming from topics: {topics}")
            
            for message in self.consumer:
                if not self.running:
                    break
                    
                logger.info(f"Received message from topic: {message.topic}, partition: {message.partition}, offset: {message.offset}")
                self.process_message(message)
                
        except KafkaError as e:
            logger.error(f"Kafka error: {e}")
        except Exception as e:
            logger.error(f"Unexpected error: {e}")
        finally:
            self.stop()
    
    def stop(self):
        self.running = False
        if self.consumer:
            self.consumer.close()
            logger.info("Consumer stopped")


class FinancialTransactionConsumer:
    def __init__(self, bootstrap_servers='localhost:9092', 
                 transaction_topic='financial-transactions',
                 fraud_topic='fraud-alerts',
                 settlement_topic='settlement-events'):
        
        self.processor = TransactionProcessor(bootstrap_servers=bootstrap_servers)
        self.topics = [transaction_topic, fraud_topic, settlement_topic]
        
        self.processor.register_handler('payment', self.handle_payment)
        self.processor.register_handler('transfer', self.handle_transfer)
        self.processor.register_handler('withdrawal', self.handle_withdrawal)
        self.processor.register_handler('deposit', self.handle_deposit)
        self.processor.register_handler('fraud_alert', self.handle_fraud_alert)
        self.processor.register_handler('settlement', self.handle_settlement)
        
    def handle_payment(self, message: Dict[str, Any]):
        logger.info(f"Processing payment transaction: {message}")
        transaction_id = message.get('transaction_id')
        amount = message.get('amount')
        currency = message.get('currency', 'USD')
        merchant = message.get('merchant')
        customer = message.get('customer')
        
        logger.info(f"Payment: ID={transaction_id}, Amount={amount} {currency}, Merchant={merchant}, Customer={customer}")
        
        if amount > 10000:
            logger.warning(f"High-value payment detected: {transaction_id}")
        
    def handle_transfer(self, message: Dict[str, Any]):
        logger.info(f"Processing transfer transaction: {message}")
        transaction_id = message.get('transaction_id')
        amount = message.get('amount')
        from_account = message.get('from_account')
        to_account = message.get('to_account')
        
        logger.info(f"Transfer: ID={transaction_id}, Amount={amount}, From={from_account}, To={to_account}")
        
    def handle_withdrawal(self, message: Dict[str, Any]):
        logger.info(f"Processing withdrawal transaction: {message}")
        transaction_id = message.get('transaction_id')
        amount = message.get('amount')
        account = message.get('account')
        atm_id = message.get('atm_id')
        
        logger.info(f"Withdrawal: ID={transaction_id}, Amount={amount}, Account={account}, ATM={atm_id}")
        
    def handle_deposit(self, message: Dict[str, Any]):
        logger.info(f"Processing deposit transaction: {message}")
        transaction_id = message.get('transaction_id')
        amount = message.get('amount')
        account = message.get('account')
        
        logger.info(f"Deposit: ID={transaction_id}, Amount={amount}, Account={account}")
        
    def handle_fraud_alert(self, message: Dict[str, Any]):
        logger.warning(f"FRAUD ALERT: {message}")
        alert_id = message.get('alert_id')
        transaction_id = message.get('transaction_id')
        risk_score = message.get('risk_score')
        reason = message.get('reason')
        
        logger.warning(f"Fraud Alert: ID={alert_id}, Transaction={transaction_id}, Risk Score={risk_score}, Reason={reason}")
        
    def handle_settlement(self, message: Dict[str, Any]):
        logger.info(f"Processing settlement event: {message}")
        settlement_id = message.get('settlement_id')
        batch_id = message.get('batch_id')
        total_amount = message.get('total_amount')
        transaction_count = message.get('transaction_count')
        
        logger.info(f"Settlement: ID={settlement_id}, Batch={batch_id}, Total={total_amount}, Count={transaction_count}")
    
    def start(self):
        logger.info("Starting Financial Transaction Consumer...")
        self.processor.start_consuming(self.topics)
    
    def stop(self):
        self.processor.stop()


class DynamicMessageHandler:
    def __init__(self, bootstrap_servers='localhost:9092', group_id='dynamic-handler-group'):
        self.processor = TransactionProcessor(bootstrap_servers=bootstrap_servers, group_id=group_id)
    
    def add_custom_handler(self, message_type: str, handler_code: str):
        try:
            exec_globals = {}
            exec(handler_code, exec_globals)
            
            if 'handler' in exec_globals:
                self.processor.register_handler(message_type, exec_globals['handler'])
                logger.info(f"Dynamic handler registered for type: {message_type}")
            else:
                logger.error("Handler code must define a function named 'handler'")
        except Exception as e:
            logger.error(f"Error loading dynamic handler: {e}")
    
    def start(self, topics):
        self.processor.start_consuming(topics)
    
    def stop(self):
        self.processor.stop()


